class DataPipeline:
    def __init__(self, source, destination):
        self.source = source
        self.destination = destination
        self.filters = []
        self.transformations = []

    def add_filter(self, condition):
        self.filters.append(condition)

    def add_transform(self, func):
        self.transformations.append(func)

    def add_validation(self, validator):
        # Mixed concerns - also does validation
        self.transformations.append(validator)

    def run(self):
        # Monolithic: reads, filters, transforms, validates, writes - all in one
        data = self.source.read()
        for f in self.filters:
            data = [row for row in data if f(row)]
        for t in self.transformations:
            data = [t(row) for row in data]
        for row in data:
            if not self._validate(row):
                continue  # Silently skips invalid rows
        self.destination.write(data)

    def _validate(self, row):
        # Scattered validation
        return row and len(row) > 0

    def get_stats(self):
        # Mixed reporting with processing
        return {"rows": len(self.data) if hasattr(self, 'data') else 0}
